// AdminServiceClient is the client API for AdminService service.
//
// For semantics around ctx use and closing/ending streaming RPCs, please refer to https://pkg.go.dev/google.golang.org/grpc/?tab=doc#ClientConn.NewStream.
//
// AdminService 集群管理服务
// 提供类似 kubectl 的集群管理 API
// 可由运维工具、CLI、Dashboard 等调用
// 当 Master 启用安全认证时，所有请求需携带有效的认证令牌
type AdminServiceClient interface {
	// ListNodes 列出节点（类似 kubectl get nodes）
	// 支持按状态、区域、标签过滤，支持分页
	ListNodes(ctx context.Context, in *ListNodesRequest, opts ...grpc.CallOption) (*ListNodesResponse, error)
	// GetNodeInfo 获取节点详情
	// 返回节点的完整信息，包括容量、连接状态、任务数等
	GetNodeInfo(ctx context.Context, in *GetNodeInfoRequest, opts ...grpc.CallOption) (*GetNodeInfoResponse, error)
	// GetClusterStats 获取集群统计（类似 kubectl top nodes）
	// 返回集群级别的聚合统计信息
	GetClusterStats(ctx context.Context, in *ClusterStatsRequest, opts ...grpc.CallOption) (*ClusterStatsResponse, error)
	// ListTasks 列出任务（类似 kubectl get jobs）
	// 支持按状态、类型、节点过滤，支持分页
	ListTasks(ctx context.Context, in *ListTasksRequest, opts ...grpc.CallOption) (*ListTasksResponse, error)
	// DrainNode 排空节点（类似 kubectl drain）
	// 通知指定节点停止接受新任务，等待已有任务完成后下线
	DrainNode(ctx context.Context, in *DrainNodeRequest, opts ...grpc.CallOption) (*DrainNodeResponse, error)
	// EvictNode 驱逐节点（类似 kubectl delete node）
	// 立即断开节点连接并将其从集群中移除
	EvictNode(ctx context.Context, in *EvictNodeRequest, opts ...grpc.CallOption) (*EvictNodeResponse, error)
	// DisableNode 停用节点（类似 kubectl cordon）
	// 标记节点为不可调度，不再接受新任务
	DisableNode(ctx context.Context, in *DisableNodeRequest, opts ...grpc.CallOption) (*DisableNodeResponse, error)
	// EnableNode 启用节点（类似 kubectl uncordon）
	// 恢复节点为可调度状态
	EnableNode(ctx context.Context, in *EnableNodeRequest, opts ...grpc.CallOption) (*EnableNodeResponse, error)
	// GetNodeTop 获取节点资源 Top（类似 kubectl top node）
	// 返回节点的实时资源使用情况
	GetNodeTop(ctx context.Context, in *GetNodeTopRequest, opts ...grpc.CallOption) (*GetNodeTopResponse, error)
	// GetNodeLogs 获取节点日志（类似 kubectl logs）
	// 获取指定节点的运行日志
	GetNodeLogs(ctx context.Context, in *GetNodeLogsRequest, opts ...grpc.CallOption) (*GetNodeLogsResponse, error)
	// Authenticate CLI 客户端认证
	// 通过预共享密钥获取访问令牌
	Authenticate(ctx context.Context, in *AuthRequest, opts ...grpc.CallOption) (*AuthResponse, error)
	// ListMasters 列出 Master 节点（类似 kubectl get nodes -l role=master）
	// 返回集群中所有 Master 节点信息
	ListMasters(ctx context.Context, in *ListMastersRequest, opts ...grpc.CallOption) (*ListMastersResponse, error)
	// ListWorkers 列出 Worker 节点（类似 kubectl get nodes -l role=worker）
	// 返回集群中所有 Worker 节点信息
	ListWorkers(ctx context.Context, in *ListWorkersRequest, opts ...grpc.CallOption) (*ListWorkersResponse, error)
	// AddTaint 给节点添加污点（类似 kubectl taint）
	AddTaint(ctx context.Context, in *AddTaintRequest, opts ...grpc.CallOption) (*AddTaintResponse, error)
	// RemoveTaint 移除节点污点
	RemoveTaint(ctx context.Context, in *RemoveTaintRequest, opts ...grpc.CallOption) (*RemoveTaintResponse, error)
}

